     1→/**
     2→ * Consent management system for data collection and privacy compliance
     3→ */
     4→
     5→export interface ConsentOptions {
     6→  /** Purpose of data collection */
     7→  purpose: string;
     8→  /** Data types being collected */
     9→  dataTypes: string[];
    10→  /** Duration of data storage */
    11→  storageDuration?: string;
    12→  /** Whether consent is required (default: true) */
    13→  required?: boolean;
    14→  /** Contact information for data privacy questions */
    15→  contactInfo?: {
    16→    email?: string;
    17→    phone?: string;
    18→    address?: string;
    19→  };
    20→  /** Link to privacy policy */
    21→  privacyPolicyUrl?: string;
    22→  /** Custom consent message */
    23→  customMessage?: string;
    24→}
    25→
    26→export interface ConsentResult {
    27→  /** Whether consent was granted */
    28→  granted: boolean;
    29→  /** Timestamp of consent decision */
    30→  timestamp: number;
    31→  /** Consent options that were presented */
    32→  options: ConsentOptions;
    33→  /** Participant ID if available */
    34→  participantId?: string;
    35→  /** Session ID */
    36→  sessionId: string;
    37→}
    38→
    39→export class ConsentManager {
    40→  private consentResults: Map<string, ConsentResult> = new Map();
    41→  private static instance: ConsentManager;
    42→
    43→  private constructor() {}
    44→
    45→  static getInstance(): ConsentManager {
    46→    if (!ConsentManager.instance) {
    47→      ConsentManager.instance = new ConsentManager();
    48→    }
    49→    return ConsentManager.instance;
    50→  }
    51→
    52→  /**
    53→   * Request consent from participant
    54→   */
    55→  async requestConsent(
    56→    sessionId: string,
    57→    options: ConsentOptions,
    58→    participantId?: string
    59→  ): Promise<ConsentResult> {
    60→    // Check if consent already granted for this session
    61→    const existingConsent = this.consentResults.get(sessionId);
    62→    if (existingConsent && existingConsent.granted) {
    63→      return existingConsent;
    64→    }
    65→
    66→    // Create consent UI
    67→    const consentResult = await this.showConsentDialog(options);
    68→    
    69→    // Store consent result
    70→    const result: ConsentResult = {
    71→      granted: consentResult,
    72→      timestamp: Date.now(),
    73→      options,
    74→      participantId,
    75→      sessionId,
    76→    };
    77→
    78→    this.consentResults.set(sessionId, result);
    79→    
    80→    // Log consent decision for compliance
    81→    console.log(`Consent ${result.granted ? 'granted' : 'denied'} for session ${sessionId}`, {
    82→      timestamp: new Date(result.timestamp).toISOString(),
    83→      purpose: options.purpose,
    84→      dataTypes: options.dataTypes,
    85→      participantId,
    86→    });
    87→
    88→    return result;
    89→  }
    90→
    91→  /**
    92→   * Get consent status for a session
    93→   */
    94→  getConsentStatus(sessionId: string): ConsentResult | null {
    95→    return this.consentResults.get(sessionId) || null;
    96→  }
    97→
    98→  /**
    99→   * Check if consent is granted for a session
   100→   */
   101→  hasConsent(sessionId: string): boolean {
   102→    const result = this.consentResults.get(sessionId);
   103→    return result?.granted || false;
   104→  }
   105→
   106→  /**
   107→   * Revoke consent for a session
   108→   */
   109→  revokeConsent(sessionId: string): void {
   110→    const result = this.consentResults.get(sessionId);
   111→    if (result) {
   112→      result.granted = false;
   113→      result.timestamp = Date.now();
   114→      console.log(`Consent revoked for session ${sessionId}`);
   115→    }
   116→  }
   117→
   118→  /**
   119→   * Get all consent records (for data audit purposes)
   120→   */
   121→  getAllConsentRecords(): ConsentResult[] {
   122→    return Array.from(this.consentResults.values());
   123→  }
   124→
   125→  /**
   126→   * Clear expired consent records
   127→   */
