    41→
    42→  async initialize(): Promise<void> {
    43→    if (this._isConnected) {
    44→      return;
    45→    }
    46→
    47→    try {
    48→      // Create audio context
    49→      this.audioContext = new (window.AudioContext ||
    50→        (window as any).webkitAudioContext)();
