    72→
    73→    // Cancel any pending animation frames
    74→    if (this.monitoringFrameId) {
    75→      cancelAnimationFrame(this.monitoringFrameId);
    76→      this.monitoringFrameId = undefined;
    77→    }
    78→
    79→    if (this.mediaStream) {
    80→      this.mediaStream.getTracks().forEach((track) => track.stop());
    81→      this.mediaStream = undefined;
    82→    }
    83→
    84→    // Properly disconnect audio nodes before closing context
    85→    if (this.microphone) {
    86→      this.microphone.disconnect();
