    97→      this.audioContext = undefined;
    98→    }
    99→
   100→    // Remove event listener using correct reference
   101→    navigator.mediaDevices?.removeEventListener(
   102→      'devicechange',
   103→      this.deviceChangeHandler,
   104→    );
   105→
   106→    this.outputNode = undefined;
   107→    this.setConnected(false);
   108→  }
   109→
   110→  async detectCapabilities(): Promise<DeviceCapabilities> {
   111→    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
   112→      return {
   113→        canDetectHotplug: false,
   114→        supportsHighPrecisionTiming: false,
