   124→
   125→    return {
   126→      canDetectHotplug: true,
   127→      supportsHighPrecisionTiming: true,
   128→      maxSampleRate: this.audioContext?.sampleRate || 48000,
   129→      supportedFormats: ['audio/wav', 'audio/webm', 'audio/ogg'],
   130→    };
   131→  }
   132→
   133→  async getAudioDevices(): Promise<AudioDeviceInfo[]> {
   134→    if (!navigator.mediaDevices || !navigator.mediaDevices.enumerateDevices) {
   135→      return [];
   136→    }
   137→
   138→    try {
   139→      const devices = await navigator.mediaDevices.enumerateDevices();
   140→      return devices
   141→        .filter(
   142→          (device) =>
   143→            device.kind === 'audioinput' || device.kind === 'audiooutput',
   144→        )
   145→        .map((device) => ({
   146→          deviceId: device.deviceId,
   147→          label: device.label,
   148→          kind: device.kind,
   149→          groupId: device.groupId,
   150→        }));
   151→    } catch (error) {
   152→      console.error('Error enumerating audio devices:', error);
   153→      return [];
   154→    }
   155→  }
   156→
   157→  async startRecording(deviceId?: string): Promise<void> {
   158→    if (this.isRecording) {
   159→      return;
   160→    }
   161→
   162→    if (!this.audioContext) {
   163→      throw new Error('Audio context not initialized');
   164→    }
   165→
   166→    try {
   167→      const constraints: MediaStreamConstraints = {
   168→        audio: deviceId ? { deviceId: { exact: deviceId } } : true,
   169→      };
   170→
   171→      this.mediaStream = await navigator.mediaDevices.getUserMedia(constraints);
