import { Device, DeviceCapabilities } from './Device.js';
import type { PrecisionClock } from '@psyforge/timing';

export interface AudioDeviceInfo {
  deviceId: string;
  label: string;
  kind: MediaDeviceKind;
  groupId: string;
}

export interface AudioEventData {
  level?: number;
  frequency?: number;
  duration?: number;
  buffer?: ArrayBuffer;
}

export class AudioDevice extends Device {
  private audioContext?: AudioContext;
  private mediaStream?: MediaStream;
  private analyser?: AnalyserNode;
  private microphone?: MediaStreamAudioSourceNode;
  private outputNode?: AudioDestinationNode;
  private isRecording: boolean = false;
  private deviceChangeHandler: () => void;
  private monitoringFrameId?: number;

  constructor(clock: PrecisionClock) {
    const capabilities: DeviceCapabilities = {
      canDetectHotplug: true,
      supportsHighPrecisionTiming: true,
      maxSampleRate: 48000,
      supportedFormats: ['audio/wav', 'audio/webm', 'audio/ogg'],
    };

    super('audio-primary', 'audio', capabilities, clock);

    // Bind event handler to maintain correct reference for removal
    this.deviceChangeHandler = this.handleDeviceChange.bind(this);
  }

  async initialize(): Promise<void> {
    if (this._isConnected) {
      return;
    }

    try {
      // Create audio context
      this.audioContext = new (window.AudioContext ||
        (window as any).webkitAudioContext)();

      // Resume context if suspended (required for some browsers)
      if (this.audioContext.state === 'suspended') {
        await this.audioContext.resume();
      }

      this.outputNode = this.audioContext.destination;
      this.setConnected(true);

      // Monitor device changes
      navigator.mediaDevices?.addEventListener(
        'devicechange',
        this.deviceChangeHandler,
      );
    } catch (error) {
      throw new Error(`Failed to initialize audio device: ${error}`);
    }
  }

  async cleanup(): Promise<void> {
    await this.stopRecording();

    // Cancel any pending animation frames
    if (this.monitoringFrameId) {
      cancelAnimationFrame(this.monitoringFrameId);
      this.monitoringFrameId = undefined;
    }

    if (this.mediaStream) {
      this.mediaStream.getTracks().forEach((track) => track.stop());
      this.mediaStream = undefined;
    }

    // Properly disconnect audio nodes before closing context
    if (this.microphone) {
      this.microphone.disconnect();
      this.microphone = undefined;
    }

    if (this.analyser) {
      this.analyser.disconnect();
      this.analyser = undefined;
    }

    if (this.audioContext) {
      await this.audioContext.close();
      this.audioContext = undefined;
    }

    // Remove event listener using correct reference
    navigator.mediaDevices?.removeEventListener(
      'devicechange',
      this.deviceChangeHandler,
    );

    this.outputNode = undefined;
    this.setConnected(false);
  }

  async detectCapabilities(): Promise<DeviceCapabilities> {
    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
      return {
        canDetectHotplug: false,
        supportsHighPrecisionTiming: false,
        maxSampleRate: 0,
        supportedFormats: [],
      };
    }

    const devices = await this.getAudioDevices();
    // TODO: Use hasInput/hasOutput for more specific capability detection
    devices.some((d) => d.kind === 'audioinput');
    devices.some((d) => d.kind === 'audiooutput');

    return {
      canDetectHotplug: true,
      supportsHighPrecisionTiming: true,
      maxSampleRate: this.audioContext?.sampleRate || 48000,
      supportedFormats: ['audio/wav', 'audio/webm', 'audio/ogg'],
    };
  }

  async getAudioDevices(): Promise<AudioDeviceInfo[]> {
    if (!navigator.mediaDevices || !navigator.mediaDevices.enumerateDevices) {
      return [];
    }

    try {
      const devices = await navigator.mediaDevices.enumerateDevices();
      return devices
        .filter(
          (device) =>
            device.kind === 'audioinput' || device.kind === 'audiooutput',
        )
        .map((device) => ({
          deviceId: device.deviceId,
          label: device.label,
          kind: device.kind,
          groupId: device.groupId,
        }));
    } catch (error) {
      console.error('Error enumerating audio devices:', error);
      return [];
    }
  }

  async startRecording(deviceId?: string): Promise<void> {
    if (this.isRecording) {
      return;
    }

    if (!this.audioContext) {
      throw new Error('Audio context not initialized');
    }

    try {
      const constraints: MediaStreamConstraints = {
        audio: deviceId ? { deviceId: { exact: deviceId } } : true,
      };

      this.mediaStream = await navigator.mediaDevices.getUserMedia(constraints);
      this.microphone = this.audioContext.createMediaStreamSource(
        this.mediaStream,
      );

      // Create analyser for audio level monitoring
      this.analyser = this.audioContext.createAnalyser();
      this.analyser.fftSize = 256;
      this.microphone.connect(this.analyser);

      this.isRecording = true;
      this.emitEvent('recordingstarted', { started: true });

      // Start monitoring audio levels
      this.monitorAudioLevel();
    } catch (error) {
      throw new Error(`Failed to start recording: ${error}`);
    }
  }

  async stopRecording(): Promise<void> {
    if (!this.isRecording) {
      return;
    }

    this.isRecording = false;

    // Cancel animation frame monitoring
    if (this.monitoringFrameId) {
      cancelAnimationFrame(this.monitoringFrameId);
      this.monitoringFrameId = undefined;
    }

    if (this.mediaStream) {
      this.mediaStream.getTracks().forEach((track) => track.stop());
    }

    if (this.microphone) {
      this.microphone.disconnect();
    }

    this.emitEvent('recordingstopped', { stopped: true });
  }

  async playSound(buffer: ArrayBuffer, volume: number = 1.0): Promise<void> {
    if (!this.audioContext || !this.outputNode) {
      throw new Error('Audio context not initialized');
