        source.removeEventListener('error', cleanup);
      }, (audioBuffer.duration + 1) * 1000); // 1 second buffer

      // Override cleanup to also clear timeout
      const originalCleanup = cleanup;
      const enhancedCleanup = () => {
        clearTimeout(timeoutId);
        originalCleanup();
        source.removeEventListener('ended', enhancedCleanup);
        source.removeEventListener('error', enhancedCleanup);
      };

      source.removeEventListener('ended', cleanup);
      source.removeEventListener('error', cleanup);
      source.addEventListener('ended', enhancedCleanup);
      source.addEventListener('error', enhancedCleanup);

      source.start(startTime);

      this.emitEvent('soundplayed', {
        duration: audioBuffer.duration,
        startTime: this.clock.now(),
      });
    } catch (error) {
      throw new Error(`Failed to play sound: ${error}`);
    }
  }

  async createTone(
    frequency: number,
    duration: number,
    volume: number = 0.5,
  ): Promise<void> {
    if (!this.audioContext || !this.outputNode) {
      throw new Error('Audio context not initialized');
    }

