/**
 * Consent management system for data collection and privacy compliance
 */

export interface ConsentOptions {
  /** Purpose of data collection */
  purpose: string;
  /** Data types being collected */
  dataTypes: string[];
  /** Duration of data storage */
  storageDuration?: string;
  /** Whether consent is required (default: true) */
  required?: boolean;
  /** Contact information for data privacy questions */
  contactInfo?: {
    email?: string;
    phone?: string;
    address?: string;
  };
  /** Link to privacy policy */
  privacyPolicyUrl?: string;
  /** Custom consent message */
  customMessage?: string;
}

export interface ConsentResult {
  /** Whether consent was granted */
  granted: boolean;
  /** Timestamp of consent decision */
  timestamp: number;
  /** Consent options that were presented */
  options: ConsentOptions;
  /** Participant ID if available */
  participantId?: string;
  /** Session ID */
  sessionId: string;
}

export class ConsentManager {
  private consentResults: Map<string, ConsentResult> = new Map();
  private static instance: ConsentManager;

  private constructor() {}

  static getInstance(): ConsentManager {
    if (!ConsentManager.instance) {
      ConsentManager.instance = new ConsentManager();
    }
    return ConsentManager.instance;
  }

  /**
   * Request consent from participant
   */
  async requestConsent(
    sessionId: string,
    options: ConsentOptions,
    participantId?: string
  ): Promise<ConsentResult> {
    // Check if consent already granted for this session
    const existingConsent = this.consentResults.get(sessionId);
    if (existingConsent && existingConsent.granted) {
      return existingConsent;
    }

    // Create consent UI
    const consentResult = await this.showConsentDialog(options);

    // Store consent result
    const result: ConsentResult = {
      granted: consentResult,
      timestamp: Date.now(),
      options,
      participantId,
      sessionId,
    };

    this.consentResults.set(sessionId, result);

    // Log consent decision for compliance
    console.log(`Consent ${result.granted ? 'granted' : 'denied'} for session ${sessionId}`, {
      timestamp: new Date(result.timestamp).toISOString(),
      purpose: options.purpose,
      dataTypes: options.dataTypes,
      participantId,
    });

    return result;
  }

  /**
   * Get consent status for a session
   */
  getConsentStatus(sessionId: string): ConsentResult | null {
    return this.consentResults.get(sessionId) || null;
  }

  /**
   * Check if consent is granted for a session
   */
  hasConsent(sessionId: string): boolean {
    const result = this.consentResults.get(sessionId);
    return result?.granted || false;
  }

  /**
   * Revoke consent for a session
   */
  revokeConsent(sessionId: string): void {
    const result = this.consentResults.get(sessionId);
    if (result) {
      result.granted = false;
      result.timestamp = Date.now();
      console.log(`Consent revoked for session ${sessionId}`);
    }
  }

  /**
   * Get all consent records (for data audit purposes)
   */
  getAllConsentRecords(): ConsentResult[] {
    return Array.from(this.consentResults.values());
  }

  /**
   * Clear expired consent records
   */
  clearExpiredConsent(maxAge: number = 24 * 60 * 60 * 1000): void {
    const now = Date.now();
    for (const [sessionId, result] of this.consentResults.entries()) {
      if (now - result.timestamp > maxAge) {
        this.consentResults.delete(sessionId);
      }
    }
  }

  /**
   * Show consent dialog to user
   */
  private async showConsentDialog(options: ConsentOptions): Promise<boolean> {
    return new Promise((resolve) => {
      // Create modal backdrop
      const backdrop = document.createElement('div');
      backdrop.style.cssText = `
        position: fixed;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        background-color: rgba(0, 0, 0, 0.5);
        display: flex;
        align-items: center;
        justify-content: center;
        z-index: 10000;
        font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
      `;

      // Create modal dialog
      const dialog = document.createElement('div');
      dialog.style.cssText = `
        background: white;
        border-radius: 8px;
        padding: 24px;
        max-width: 600px;
        max-height: 80vh;
        overflow-y: auto;
        box-shadow: 0 4px 20px rgba(0, 0, 0, 0.15);
        margin: 20px;
      `;

      // Create content
      const title = document.createElement('h2');
      title.style.cssText = `
        margin: 0 0 16px 0;
        color: #1f2937;
        font-size: 20px;
        font-weight: 600;
      `;
      title.textContent = 'Data Collection Consent';

      const message = document.createElement('div');
      message.style.cssText = `
        margin-bottom: 20px;
        color: #374151;
        line-height: 1.6;
      `;

      const defaultMessage = `
        <p><strong>Purpose:</strong> ${this.escapeHtml(options.purpose)}</p>
        <p><strong>Data Types:</strong> ${options.dataTypes.map(dt => this.escapeHtml(dt)).join(', ')}</p>
        ${options.storageDuration ? `<p><strong>Storage Duration:</strong> ${this.escapeHtml(options.storageDuration)}</p>` : ''}
        ${options.contactInfo?.email ? `<p><strong>Contact:</strong> ${this.escapeHtml(options.contactInfo.email)}</p>` : ''}
        ${options.privacyPolicyUrl ? `<p><a href="${this.escapeHtml(options.privacyPolicyUrl)}" target="_blank" rel="noopener noreferrer">View Privacy Policy</a></p>` : ''}
        <p>Do you consent to this data collection?</p>
      `;

      message.innerHTML = options.customMessage || defaultMessage;

      // Create buttons
      const buttonContainer = document.createElement('div');
      buttonContainer.style.cssText = `
        display: flex;
        gap: 12px;
        justify-content: flex-end;
        margin-top: 24px;
      `;

      const denyButton = document.createElement('button');
      denyButton.style.cssText = `
        padding: 8px 16px;
        border: 1px solid #d1d5db;
        background: white;
        color: #374151;
        border-radius: 4px;
        cursor: pointer;
        font-size: 14px;
        font-weight: 500;
      `;
      denyButton.textContent = 'Deny';
      denyButton.onclick = () => {
        document.body.removeChild(backdrop);
        resolve(false);
      };

      const acceptButton = document.createElement('button');
      acceptButton.style.cssText = `
        padding: 8px 16px;
        border: none;
        background: #3b82f6;
        color: white;
        border-radius: 4px;
        cursor: pointer;
        font-size: 14px;
        font-weight: 500;
      `;
      acceptButton.textContent = 'Accept';
      acceptButton.onclick = () => {
        document.body.removeChild(backdrop);
        resolve(true);
      };

      // Add hover effects
      denyButton.onmouseover = () => {
        denyButton.style.backgroundColor = '#f3f4f6';
      };
      denyButton.onmouseout = () => {
        denyButton.style.backgroundColor = 'white';
      };

      acceptButton.onmouseover = () => {
        acceptButton.style.backgroundColor = '#2563eb';
      };
      acceptButton.onmouseout = () => {
        acceptButton.style.backgroundColor = '#3b82f6';
      };

      // Assemble dialog
      buttonContainer.appendChild(denyButton);
      buttonContainer.appendChild(acceptButton);

      dialog.appendChild(title);
      dialog.appendChild(message);
      dialog.appendChild(buttonContainer);

      backdrop.appendChild(dialog);
      document.body.appendChild(backdrop);

      // Focus accept button
      acceptButton.focus();

      // Handle ESC key
      const handleEsc = (e: KeyboardEvent) => {
        if (e.key === 'Escape') {
          document.removeEventListener('keydown', handleEsc);
          document.body.removeChild(backdrop);
          resolve(false);
        }
      };
      document.addEventListener('keydown', handleEsc);
    });
  }

  /**
   * Escape HTML to prevent XSS
   */
  private escapeHtml(text: string): string {
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
  }
}

